noncompliant:
switch (i) {
  case 5 ... 1: // Noncompliant: empty range (5 > 1)
    //...
    break;
}

switch (value) {
  case 10 ... 5: // Noncompliant: empty range
    processValue();
    break;
}

switch (ch) {
  case 'z' ... 'a': // Noncompliant: empty range
    processChar();
    break;
}

compliant:
switch (i) {
  case 1 ... 5: // Compliant: valid range
    //...
    break;
}

switch (value) {
  case 5 ... 10: // Compliant: valid range
    processValue();
    break;
}

switch (ch) {
  case 'a' ... 'z': // Compliant: valid range
    processChar();
    break;
}
